            <Show when={saveMsg()}>
              <span
                class={`text-sm ${saveMsg()!.type === 'success' ? 'text-green-600' : 'text-red-600'}`}
              >
                {saveMsg()!.text}
              </span>
            </Show>
          </div>
        </div>

        {/* ── Admin users ── */}
        <div class="card">
          <h3 class="text-lg font-semibold text-gray-900 mb-4">Admin Users</h3>

