#### 3C. `apps/work-orders/src/pages/WorkOrderDetail.tsx` — Step progress panel

Add a StepProgressPanel component to the work order detail page:

```tsx
function StepProgressPanel(props: { workOrderId: string }) {
    const [progress, { refetch }] = createResource(
        () => props.workOrderId,
        (id) => api.getStepProgress(id)
    );

    const initSteps = async () => {
        await api.initializeSteps(props.workOrderId);
        refetch();
    };

    const updateStep = async (progressId: string, status: string) => {
        await api.updateStepProgress(progressId, { status } as any);
        refetch();
    };

    return (
        <div class="mt-6">
            <h3 class="text-lg font-semibold mb-4">Procedure Steps</h3>
            <Show when={progress()?.length} fallback={
                <button onClick={initSteps} class="btn btn-primary">
                    Initialize Steps from SOP
                </button>
            }>
                <div class="space-y-2">
                    <For each={progress()!}>
                        {(step) => (
                            <div class={`flex items-center gap-3 p-3 rounded border ${
                                step.status === 'completed' ? 'bg-green-50 border-green-200' :
                                step.status === 'in_progress' ? 'bg-yellow-50 border-yellow-200' :
                                'bg-white border-gray-200'
                            }`}>
                                <select
                                    value={step.status}
                                    onChange={(e) => updateStep(step.id, e.target.value)}
                                    class="text-sm border rounded px-2 py-1"
                                >
                                    <option value="pending">Pending</option>
                                    <option value="in_progress">In Progress</option>
                                    <option value="completed">Completed</option>
                                    <option value="skipped">Skipped</option>
                                    <option value="blocked">Blocked</option>
                                </select>
                                <div class="flex-1">
                                    <span class="font-medium text-sm">
                                        {step.sop_step?.phase_name} - Step {step.sop_step?.step_number}: {step.sop_step?.step_name}
                                    </span>
                                    <Show when={step.sop_step?.tasks_summary}>
                                        <p class="text-xs text-gray-500 mt-1">{step.sop_step!.tasks_summary}</p>
                                    </Show>
                                </div>
                                <Show when={step.duration_minutes}>
                                    <span class="text-xs text-gray-500">{step.duration_minutes}m</span>
                                </Show>
                            </div>
                        )}
                    </For>
                </div>
            </Show>
        </div>
    );
}
```

